What does this program print?

```cpp
#include <iostream>
template <typename T>
class Box {
public:
    T value;
    Box(T v) : value{v} {}
    void show() const { std::cout << value * 2 << "\n"; }
};
int main() {
    Box<int> a{5};
    Box<double> b{1.5};
    a.show();
    b.show();
}
```

What does this program print?

```cpp
#include <iostream>
template <typename T>
class Wrap {
    T v_;
public:
    Wrap(T v) : v_{v} {}
    T get() const { return v_; }
};
template <typename T>
T Wrap<T>::get() const { return v_; }  // duplicate definition
int main() {
    Wrap<int> w{7};
    std::cout << w.get() << "\n";
}
```

